在 rust 中，可以不用宣告型別，也會由編譯器自行推定 fn main () { let x = 5; // 會被自行推定為 i32 let y: i32 = 10; // 也可以宣告變數型別
} 預設所有變數都是不可變的 fn main () { let x = 5; x = 10; // 不可以改變 x 的值
} 若要改變變數，必須宣告 mut fn main () { let mut x = 5; x = 10; // OK
} 可以用 tuple 或 struct 的方式宣告多個變數並同時賦值 fn main () { let (a, b) = (1, 2); let (mut x, mut y) = (1, 2); // 或宣告可變的變數
} 可以事先宣告變數，但若變數被宣告後沒有初始化，同時在之後被使用到，會編譯不過 fn main () { let x: i32; println!("{}", x); // use of possibly-uninitialized `x`
}
fn main () { let x: i32; let condition = true; if condition { x = 1; // 因為在這裡被初始化了 println!("{}", x); // 所以可以使用 } // 但在這裡沒有被初始化 println!("{}", x); // 在這裡會出錯
