}
#[allow(unused_mut)]
fn main () { let mut x = Person { age: 16 }; let y = &x; // 不可變借用，擁有者是 x，借用者是 y println!("{:p}", &x); // x 可以再進行不可變借用 // cannot borrow `x` as mutable because it is also borrowed as immutable // 但不可以再進行可變借用 birthday(&mut x); println!("{:?}", y); // 借用者 y 可以使用 x，印出值
} 在可變借用期間 (可變)，擁有者不能存取 Value，也不能進行不可變借用 (不共享) #[derive(Debug)]
struct Person { age: i32
}
#[allow(dead_code)]
fn birthday (y: &mut Person) { y.age = y.age + 1;
}
#[allow(unused_mut)]
fn main () { let mut x = Person { age: 16 }; let y = &mut x; // 可變借用，擁有者是 x，借用者是 y y.age = 1; // cannot borrow `x` as immutable because it is also borrowed as mutable // x 不可以再進行不可變借用 println!("{:p}", &x); // cannot borrow `x` as mutable more than once at a time // 當然也不可以再進行可變借用 birthday(&mut x); // cannot use `x.age` because it was mutably borrowed // 同時你也不可以存取 x y.age = x.age + 1; println!("{:?}", y); // 借用者 y 可以使用 x，印出值
