Lexical-Lifetime 是指說生命周期與變數的作用域是綁定在一起的 舉個例子 #[derive(Debug)]
struct Person { age: i32
}
fn birthday (y: &mut Person) { y.age = y.age + 1;
}
fn life_again_gun (y: &mut Person) -> &mut Person { y.age = 0; y
}
fn main () { let mut x = Person { age: 16 }; let y = life_again_gun(&mut x); // 在 Lexical-Lifetime 的情況，y 的生命周期沒有結束 // 所以 y 還在進行可變借用 // 那理論上 x 就不可以再度可變出借 // (NLL 好像已經是標準了，所以我無法實現 LL 的編譯錯誤) birthday(&mut x); println!("{:?}", x);
} Non-Lexical-Lifetime borrow checker 的分析結構方式從 AST 轉向 MIR AST 是抽象語法樹，它會以樹狀的形式表現程式語言的語法結構，因為舊的 borrow checker 用 AST 做分析，所以會造成生命周期與作用域掛鉤 MIR 是中間表達式，他在編譯器內部會有像是流程圖的資料結構，用流程控制的方式去分析生命周期 只要變數在後面的程式碼中，沒有機會被使用到，就會提早被結束生命周期 NLL 將作用域與生命周期拆開來看了 NLL 縮短了過長的生命周期 (縮減了變數的生命)，讓程式不會充滿一堆 block 去迴避 LL 造成的問題 舉例來說 #[derive(Debug)]
struct Person { age: i32
}
fn birthday (y: &mut Person) { y.age = y.age + 1;
}
fn life_again_gun (y: &mut Person) -> &mut Person { y.age = 0; y
}
fn main () { let mut x = Person { age: 16 }; let y = life_again_gun(&mut x); // 在 Non-Lexical-Lifetime 的情況 // y 在這段程式碼的後面都沒有被使用到 // y 的生命周期就結束了 // 那這裡就不會有問題 birthday(&mut x); println!("{:?}", x);
} #[derive(Debug)]
struct Person { age: i32
}
fn birthday (y: &mut Person) { y.age = y.age + 1;
}
fn life_again_gun (y: &mut Person) -> &mut Person { y.age = 0; y
}
fn main () { let mut x = Person { age: 16 }; let y = life_again_gun(&mut x); // cannot borrow `x` as mutable more than once at a time // 但如果 y 在後面有機會被使用到 // 就代表 y 的生命周期還沒有結束 // 所以 x 不可以再度進行可變出借 birthday(&mut x); y.age = 16; println!("{:?}", x);
}

