1.8.1 反射的定義 反射指，編譯時不知道變量的具體類型，運行時（Run time）可以訪問、檢測和修改狀態或行為的能力。 reflect包定義了接口和結構體，獲取類型信息。 reflect.Type接口提供類型信息 reflect.Value結構體提供值相關信息，可以獲取甚至改變類型的值 func TypeOf(i interface{}) Type
func ValueOf(i interface{}) Value 1.8.2 反射的三大法則 接口類型變量轉換為反射類型對象 package main import ( "fmt" "reflect"
) func main() { var x float64 = 3.4 fmt.Println("type:", reflect.TypeOf(x)) fmt.Println("value:", reflect.ValueOf(x)) v := reflect.ValueOf(x) fmt.Println("type:", v.Type()) fmt.Println("kind is float64:", v.Kind() == reflect.Float64) fmt.Println("value:", v.Float())
}
//輸出
//type: float64
//value: 3.4
//kind is float64: true
//type: float64
//value: 3.4 反射類型對象轉換為接口類型變量 func (v Value) Interface() interface{}
y := v.Interface().(float64)
fmt.Println(y)
package main import ( "fmt" "reflect"
) func main() { var name interface{} = "shirdon" fmt.Printf("原始接口變量類型為%T，值為%v\n", name, name) t := reflect.TypeOf(name) v := reflect.ValueOf(name) fmt.Printf("Type類型為%T，值為%v\n", t, t) fmt.Printf("Value類型為%T，值為%v\n", v, v) i := v.Interface() fmt.Printf("新對象interface{}類型為%T，值為%v\n", i, i)
}
//輸出
//原始接口變量類型為string，值為shirdon
//Type類型為*reflect.rtype，值為string
//Value類型為reflect.Value，值為shirdon
//新對象interface{}類型為string，值為shirdon 修改反射類型對象，其值必須是可寫的（settable） reflect.TypeOf()和reflect.ValueOf()函數中若傳遞的不是指針，則只是變量復制，對該反射對象修改，不會影響原始變量。 反射對象可寫性要點: 變量指針創建的反射對象 CanSet()可判斷 Elem()返回指針指向的數據 package main import ( "fmt" "reflect"
) func main() { var name string = "shirdon" //var name int = 12 v1 := reflect.ValueOf(&name) v2 := v1.Elem() fmt.Println("可寫性:", v1.CanSet()) fmt.Println("可寫性:", v2.CanSet())
} //輸出
//可寫性：false
//可寫性：true
