package main import ( "log" "os" "text/template"
) func main() { //創建一個模版 rangeTemplate := `
{{if .Kind}}
{{range $i, $v := .MapContent}}
{{$i}} => {{$v}} , {{$.OutsideContent}}
{{end}}
{{else}}
{{range .MapContent}}
{{.}} , {{$.OutsideContent}}
{{end}} {{end}}` str1 := []string{"第一次 range", "用 index 和 value"} str2 := []string{"第二次 range", "沒有用 index 和 value"} type Content struct { MapContent []string OutsideContent string Kind bool } var contents = []Content{ {str1, "第一次外面的內容", true}, {str2, "第二次外面的內容", false}, } // 創建模板並將字符解析進去 t := template.Must(template.New("range").Parse(rangeTemplate)) // 接收並執行模板 for _, c := range contents { err := t.Execute(os.Stdout, c) if err != nil { log.Println("executing template:", err) } }
}
