建立 gRPC 服務的第一步是在.proto 檔案中定義好介面，proto是一個協議檔案，客戶端和伺服器的通訊介面正是通過proto檔案協定的，可以根據不同語言生成對應語言的程式碼檔案。這個協議檔案主要就是定義好服務（service）介面，以及請求引數和相應結果的資料結構，具體的proto語法參見如下連結（https://www.jianshu.com/p/da7ed5914088），關於二維陣列、字典等python中常用的資料型別，proto語法的表達見連結（https://blog.csdn.net/xiaoxiaojie521/article/details/106938519），下面是一個簡單的例子。 syntax = "proto3"; option cc_generic_services = true; //定義服務介面
service GrpcService { rpc hello (HelloRequest) returns (HelloResponse) {} //一個服務中可以定義多個介面，也就是多個函式功能
} //請求的引數
message HelloRequest { string data = 1; //數字1,2是引數的位置順序，並不是對引數賦值 Skill skill = 2; //支援自定義的資料格式，非常靈活
}; //返回的物件
message HelloResponse { string result = 1; map<string, int32> map_result = 2; //支援map資料格式，類似dict
}; message Skill { string name = 1;
};

