#! /usr/bin/env python
# coding=utf8 import time
from concurrent import futures import grpc from gRPC_example import hello_pb2_grpc, hello_pb2 _ONE_DAY_IN_SECONDS = 60 * 60 * 24 class TestService(hello_pb2_grpc.GrpcServiceServicer): ''' 繼承GrpcServiceServicer,實現hello方法 ''' def __init__(self): pass def hello(self, request, context): ''' 具體實現hello的方法，並按照pb的返回物件構造HelloResponse返回 :param request: :param context: :return: ''' result = request.data + request.skill.name + " this is gprc test service" list_result = {"12": 1232} return hello_pb2.HelloResponse(result=str(result), map_result=list_result) def run(): ''' 模擬服務啟動 :return: ''' server = grpc.server(futures.ThreadPoolExecutor(max_workers=10)) hello_pb2_grpc.add_GrpcServiceServicer_to_server(TestService(),server) server.add_insecure_port('[::]:50052') server.start() print("start service...") try: while True: time.sleep(_ONE_DAY_IN_SECONDS) except KeyboardInterrupt: server.stop(0) if __name__ == '__main__': run() 在服務端側，需要實現hello的方法來滿足proto檔案中GrpcService的介面需求，hello方法的傳入引數，是在proto檔案中定義的HelloRequest，context是保留欄位，不用管，返回引數則是在proto中定義的HelloResponse，服務啟動的程式碼是標準的，可以根據需求修改提供服務的ip地址以及埠號。

